    74|// Direct OpenAI API — bare model names (no openai/ prefix, that was Vercel AI Gateway routing).
    75|// gpt-4o gives real image + document analysis. Override with IVX_AI_MODEL if needed.
    76|const DEFAULT_IVX_AI_MODEL = readTrimmed(process.env.IVX_AI_MODEL)?.replace(/^openai\//, '') || 'gpt-4o';
    77|
    78|// Adaptive timeout floor / ceiling. Short prompts resolve fast (floor), large
    79|// reports get more headroom (ceiling). Tuned so a 12k-token report has ~90s
    80|// to complete instead of dying at the legacy 8s wall.
    81|const IVX_AI_TIMEOUT_FLOOR_MS = (() => {
    82|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_MS) || '15000', 10);
    83|  return Number.isFinite(raw) && raw > 0 ? raw : 15_000;
    84|})();
    85|const IVX_AI_TIMEOUT_CEIL_MS = (() => {
    86|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_CEIL_MS) || '120000', 10);
