    90|/**
    91| * Compute an adaptive hard timeout based on the size of the work.
    92| *
    93| * Budget heuristics:
    94| *  - Base latency: floor (covers handshake + first-token latency)
    95| *  - Output budget: ~50ms per maxOutputToken (gpt-4o-mini sustains ~20 tok/s)
    96| *  - Prompt budget: ~2ms per prompt char (covers large context ingestion)
    97| * Clamped to [floor, ceiling].
    98| */
    99|export function computeAdaptiveTimeoutMs(input: {
   100|  promptChars: number;
   101|  maxOutputTokens: number | null | undefined;
   102|}): number {
   103|  const outputBudget = (input.maxOutputTokens ?? 1500) * 50;
   104|  const promptBudget = input.promptChars * 2;
   105|  const budget = IVX_AI_TIMEOUT_FLOOR_MS + outputBudget + promptBudget;
   106|  return Math.min(IVX_AI_TIMEOUT_CEIL_MS, Math.max(IVX_AI_TIMEOUT_FLOOR_MS, budget));
