   109|function runWithHardTimeout<T>(label: string, promise: Promise<T>, timeoutMs: number): Promise<T> {
   110|  return new Promise<T>((resolve, reject) => {
   111|    const timer = setTimeout(() => {
   112|      const err = new Error(`${label} timed out after ${timeoutMs}ms`);
   113|      err.name = 'IVXAIGatewayTimeoutError';
   114|      reject(err);
   115|    }, timeoutMs);
   116|    promise.then(
   117|      (value) => {
   118|        clearTimeout(timer);
   119|        resolve(value);
   120|      },
   121|      (error) => {
   122|        clearTimeout(timer);
   123|        reject(error);
   124|      },
   125|    );
   126|  });
   127|}
