   137|// Backend talks directly to the OpenAI API. OPENAI_API_KEY is the primary
   138|// key; AI_GATEWAY_API_KEY is kept as a backward-compat fallback.
   139|function getIVXAIGatewayRootUrl(): string {
   140|  const configured = readTrimmed(process.env.IVX_AI_GATEWAY_URL);
   141|  // Rork independence guard (2026-07-07): never honor a gateway URL that
   142|  // points at a Rork-hosted domain, even if a stale env var is still set on
   143|  // the host. This makes the runtime self-healing: production cannot route
   144|  // through toolkit.rork.com regardless of env var state.
   145|  if (configured && !isRorkDomain(configured)) {
   146|    return configured;
   147|  }
   148|  return 'https://api.openai.com/v1';
   149|}
   150|
   151|function getIVXAIGatewayApiKey(): string {
   152|  return readTrimmed(process.env.OPENAI_API_KEY) || readTrimmed(process.env.AI_GATEWAY_API_KEY);
   153|}
   154|
   155|function buildGatewayBaseUrl(rootUrl: string): string | null {
   156|  const trimmed = readTrimmed(rootUrl).replace(/\/+$/, '');
   157|  return trimmed || null;
   158|}
   159|
   160|function getGatewayBaseUrl(): string | null {
