   162|}
   163|
   164|function isRorkDomain(url: string): boolean {
   165|  const lower = url.toLowerCase();
   166|  return lower.includes('toolkit.rork.com')
   167|    || lower.includes('api.rork.com')
   168|    || lower.endsWith('.rork.com')
   169|    || lower.includes('rork-direct.workers.dev');
