   171|
   172|function getGatewayBaseUrlCandidates(): string[] {
   173|  const configured = getGatewayBaseUrl();
   174|  const canonical = buildGatewayBaseUrl('https://api.openai.com/v1');
   175|  // Always include the canonical Vercel gateway as a fallback candidate so a
   176|  // misconfigured IVX_AI_GATEWAY_URL cannot strand the backend on a proxy that
   177|  // strips auth headers (which causes free-tier 429s on a paid account).
   178|  //
   179|  // Rork toolkit cutover (2026-07-07): the Rork toolkit URL is no longer a
   180|  // candidate. The IVX AI runtime now relies exclusively on IVX-owned
   181|  // providers: the Vercel AI Gateway (AI_GATEWAY_API_KEY) as primary, and
   182|  // OpenAI direct / Anthropic direct as fallbacks (see
   183|  // ivx-ai-provider-fallback.ts). If none of these keys are configured the
   184|  // runtime throws a clear configuration error instead of silently falling
   185|  // back to a Rork-hosted endpoint.
   186|  //
   187|  // Rork independence guard (2026-07-07): any candidate that resolves to a
   188|  // Rork domain is filtered out, so a stale IVX_AI_GATEWAY_URL env var on the
   189|  // host cannot silently re-route production through toolkit.rork.com.
   190|  const candidates = [configured, canonical].filter((c): c is string => c !== null && !isRorkDomain(c));
   191|
   192|  return [...new Set(candidates)];
   193|}
   194|
   195|function ensureIVXAIGatewayEnvironment(): void {
   196|  const apiKey = getIVXAIGatewayApiKey();
   197|  if (!apiKey) {
   198|    throw new Error(
   199|      'IVX AI runtime is not configured. Set OPENAI_API_KEY on the backend host.',
   200|    );
   201|  }
   202|}
   203|
   204|
   205|function readRecord(value: unknown): Record<string, unknown> {
   206|  return typeof value === 'object' && value !== null ? value as Record<string, unknown> : {};
   207|}
   208|
   209|function extractGatewayFailureContext(error: unknown): { status: number | null; responseBody: unknown } {
   210|  const record = readRecord(error);
   211|  const response = readRecord(record.response);
   212|  const cause = readRecord(record.cause);
   213|  const status = typeof record.statusCode === 'number'
   214|    ? record.statusCode
   215|    : typeof record.status === 'number'
   216|      ? record.status
   217|      : typeof record.responseStatus === 'number'
   218|        ? record.responseStatus
   219|        : typeof response.status === 'number'
   220|          ? response.status
   221|          : typeof cause.status === 'number'
   222|            ? cause.status
   223|            : null;
   224|  const responseBody = record.responseBody
   225|    ?? response.body
   226|    ?? response.data
   227|    ?? record.data
   228|    ?? record.body
   229|    ?? cause.responseBody
   230|    ?? cause.body
   231|    ?? null;
   232|  return { status, responseBody };
   233|}
   234|
   235|function normalizeGatewayFailure(error: unknown, context: IVXAIGatewayFailureContext): Error {
   236|  const message = error instanceof Error ? error.message : 'Gateway request failed';
   237|  const body = typeof context.responseBody === 'string'
   238|    ? context.responseBody.slice(0, 600)
   239|    : context.responseBody && typeof context.responseBody === 'object'
   240|      ? JSON.stringify(context.responseBody).slice(0, 600)
   241|      : null;
   242|  const detail = [
   243|    `IVX AI gateway request failed for ${context.module}.`,
   244|    `endpoint=${context.endpoint ?? 'unresolved'}`,
   245|    `model=${context.model}`,
   246|    context.status ? `status=${context.status}` : null,
   247|    `providerError=${message}`,
   248|    body ? `responseBody=${body}` : null,
   249|  ].filter(Boolean).join(' ');
   250|  const normalized = new Error(detail);
   251|  normalized.name = 'IVXAIGatewayRequestError';
   252|  return normalized;
   253|}
