   280|/** Strip the openai/ prefix used by the old Vercel AI Gateway routing. */
   281|function stripOpenaiPrefix(model: string): string {
   282|  return model.replace(/^openai\//, '');
   283|}
   284|
   285|export function getIVXAIEndpoint(model: string = DEFAULT_IVX_AI_MODEL): string | null {
   286|  const baseUrl = getGatewayBaseUrl();
   287|  if (!baseUrl) {
   288|    return null;
   289|  }
   290|
   291|  return `${baseUrl}/${model}`;
