   296|}
   297|
   298|export function getIVXAIConfigurationSnapshot(model: string = DEFAULT_IVX_AI_MODEL): IVXAIConfigurationSnapshot {
   299|  const hasGatewayUrl = getIVXAIGatewayRootUrl().length > 0;
   300|  const hasGatewayApiKey = getIVXAIGatewayApiKey().length > 0;
   301|  return {
   302|    configured: hasGatewayUrl && hasGatewayApiKey,
   303|    hasGatewayUrl,
   304|    hasGatewayApiKey,
   305|    model,
   306|    endpoint: getIVXAIEndpoint(model),
   307|    runtime: 'openai_direct',
   308|    layer: 'ivx_ai_runtime_wrapper',
   309|    phase: 'agent_runtime_v2',
   310|  };
   311|}
   312|
   313|export async function requestIVXAIText(input: {
   314|  module: IVXAIModule;
   315|  requestId?: string | null;
   316|  model?: string | null;
   317|  system?: string | null;
   318|  prompt?: string | null;
   319|  messages?: IVXAITextMessage[];
   320|  images?: IVXAIImageAttachment[];
   321|  files?: IVXAIFileAttachment[];
   322|  maxOutputTokens?: number;
   323|}): Promise<IVXAITextResult> {
   324|  const model = resolveIVXAIModel(input.model);
   325|  const endpoint = getIVXAIEndpoint(model);
   326|  const messages = normalizeMessages(input.messages);
   327|  const prompt = readTrimmed(input.prompt);
   328|  const system = readTrimmed(input.system);
   329|  const images = (input.images ?? [])
   330|    .map((img) => ({ url: readTrimmed(img.url), mimeType: readTrimmed(img.mimeType ?? '') || null }))
   331|    .filter((img) => img.url.length > 0);
   332|  const files = (input.files ?? []).filter(
   333|    (file) => readTrimmed(file.mediaType).length > 0 && file.data != null,
   334|  );
   335|
   336|  if (!prompt && messages.length === 0) {
   337|    throw new Error('IVX AI request requires a prompt or messages.');
   338|  }
   339|
   340|  const baseUrlCandidates = getGatewayBaseUrlCandidates();
   341|  if (baseUrlCandidates.length === 0) {
   342|    throw new Error('IVX AI runtime is not configured.');
   343|  }
   344|
   345|  console.log('[IVXAI] Routing request through IVX AI Phase 1 wrapper:', {
   346|    module: input.module,
   347|    requestId: input.requestId ?? null,
   348|    model,
   349|    endpoint,
   350|    baseUrlCandidates,
   351|    hasSystem: system.length > 0,
   352|    promptLength: prompt.length,
   353|    messageCount: messages.length,
   354|    authKeySource: 'OPENAI_API_KEY',
   355|    requestShape: messages.length > 0 ? 'messages' : 'prompt',
   356|    maxOutputTokens: input.maxOutputTokens ?? null,
   357|    phase: 'agent_runtime_v2',
   358|    layer: 'ivx_ai_runtime_wrapper',
   359|  });
   360|
   361|  // Adaptive timeout + queue gating: long prompts/reports get more time and a
   362|  // dedicated lane so they cannot block normal chat under contention.
   363|  const promptChars = prompt.length + system.length + messages.reduce((sum, m) => sum + m.content.length, 0);
   364|  const adaptiveTimeoutMs = computeAdaptiveTimeoutMs({ promptChars, maxOutputTokens: input.maxOutputTokens });
   365|  const queueLane: IVXAIQueueLane = classifyRequestLane({ promptChars, maxOutputTokens: input.maxOutputTokens });
   366|  const queueSlot = await acquireAIQueueSlot(queueLane);
   367|  const callStartedAt = Date.now();
   368|
   369|  let result: Awaited<ReturnType<typeof generateText>> | null = null;
   370|  let lastError: unknown = null;
   371|  let lastFailure: { status: number | null; responseBody: unknown } = { status: null, responseBody: null };
   372|  let successfulBaseUrl = baseUrlCandidates[0];
   373|  let retryCount = 0;
   374|
   375|  for (const baseURL of baseUrlCandidates) {
   376|    ensureIVXAIGatewayEnvironment();
   377|    try {
   378|      const gatewayProvider = createOpenAI({
   379|        apiKey: getIVXAIGatewayApiKey(),
   380|        baseURL,
   381|      });
   382|      const callTimeoutMs = adaptiveTimeoutMs;
   383|      if (images.length > 0 || files.length > 0) {
   384|        // Multimodal request: build a single user message with text + image/file
   385|        // parts so multimodal models (gpt-4o family for images/PDF OCR, video-
   386|        // capable models for video) can actually see the attachments.
   387|        const baseMessages = messages.length > 0
   388|          ? messages.slice(0, -1)
   389|          : [];
   390|        const lastTextMessage = messages.length > 0 ? messages[messages.length - 1] : null;
   391|        const userText = readTrimmed(
   392|          (lastTextMessage && lastTextMessage.role === 'user' ? lastTextMessage.content : '') || prompt
   393|        ) || 'Describe the attached file(s).';
   394|        const multimodalUser = {
   395|          role: 'user' as const,
   396|          content: [
   397|            { type: 'text' as const, text: userText },
   398|            ...images.map((img) => ({ type: 'image' as const, image: img.url })),
   399|            ...files.map((file) => ({ type: 'file' as const, data: file.data, mediaType: file.mediaType })),
   400|          ],
   401|        };
   402|        const finalMessages = lastTextMessage && lastTextMessage.role === 'user'
   403|          ? [...baseMessages, multimodalUser]
   404|          : [...messages, multimodalUser];
   405|        result = await runWithHardTimeout('IVX AI gateway (multimodal)', generateText({
   406|          model: gatewayProvider(model),
   407|          system: system.length > 0 ? system : undefined,
   408|          maxOutputTokens: input.maxOutputTokens,
   409|          // eslint-disable-next-line @typescript-eslint/no-explicit-any
   410|          messages: finalMessages as any,
   411|        }), callTimeoutMs);
   412|      } else {
   413|        result = messages.length > 0
   414|          ? await runWithHardTimeout('IVX AI gateway (messages)', generateText({
   415|              model: gatewayProvider(model),
   416|              system: system.length > 0 ? system : undefined,
   417|              maxOutputTokens: input.maxOutputTokens,
   418|              messages,
   419|            }), callTimeoutMs)
   420|          : await runWithHardTimeout('IVX AI gateway (prompt)', generateText({
   421|              model: gatewayProvider(model),
   422|              system: system.length > 0 ? system : undefined,
   423|              maxOutputTokens: input.maxOutputTokens,
   424|              prompt,
   425|            }), callTimeoutMs);
   426|      }
   427|      successfulBaseUrl = baseURL;
   428|      break;
   429|    } catch (error) {
   430|      retryCount += 1;
   431|      const failure = extractGatewayFailureContext(error);
   432|      lastError = error;
   433|      lastFailure = failure;
   434|      console.error('[IVXAI] Gateway request failed:', {
   435|        module: input.module,
   436|        requestId: input.requestId ?? null,
   437|        model,
   438|            endpoint: `${baseURL}/${model}`,
   439|        status: failure.status,
   440|        error: error instanceof Error ? error.message : 'Gateway request failed',
   441|        responseBodyType: typeof failure.responseBody,
   442|        responseBodyPreview: typeof failure.responseBody === 'string'
   443|          ? failure.responseBody.slice(0, 400)
   444|          : failure.responseBody && typeof failure.responseBody === 'object'
   445|            ? JSON.stringify(failure.responseBody).slice(0, 400)
   446|            : null,
   447|        errorName: error instanceof Error ? error.name : null,
   448|      });
   449|    }
   450|  }
   451|
   452|  if (!result) {
   453|    queueSlot.release();
   454|    const failureMessage = lastError instanceof Error ? lastError.message : 'Gateway request failed';
   455|    const isTimeout = lastError instanceof Error && lastError.name === 'IVXAIGatewayTimeoutError';
   456|
   457|    // Multi-provider fallback chain. Only invoked when:
   458|    //   - all primary gateway base URLs failed
   459|    //   - failure is in a retryable class (timeout / rate_limit / quota / 5xx / network)
   460|    //   - at least one fallback provider has its env key configured
   461|    // Fallbacks NEVER log API keys or prompt content.
   462|    const failureClass = classifyProviderFailure(lastError);
   463|    if (isFailureRetryable(failureClass)) {
   464|      const fallbackResult = await attemptProviderFallback({
   465|        module: String(input.module),
   466|        requestId: input.requestId ?? null,
   467|        system,
   468|        prompt,
   469|        messages,
   470|        maxOutputTokens: input.maxOutputTokens ?? null,
   471|        timeoutMs: adaptiveTimeoutMs,
   472|      });
   473|      if (fallbackResult) {
   474|        const fallbackMetadata: IVXAIProviderMetadata = {
   475|          provider: 'chatgpt',
   476|          source: 'remote_api',
   477|          model: fallbackResult.model,
   478|          endpoint: null,
   479|          runtime: 'ivx_ai_gateway',
   480|          ivxAI: {
   481|            architecture: 'ivx-ai',
   482|            phase: 'agent_runtime_v2',
   483|            layer: 'ivx_ai_runtime_wrapper',
   484|            module: input.module,
   485|            providerDependency: 'chatgpt_current_baseline',
   486|            requestId: input.requestId ?? null,
   487|            generatedAt: nowIso(),
   488|          },
   489|        };
