    46| * answer also carries real proof (raw command output), because a genuine run can
    47| * legitimately say e.g. "reviewed" alongside the evidence.
    48| */
    49|export const BANNED_NARRATIVE_PHRASES: readonly string[] = [
    50|  'i reviewed',
    51|  'i have reviewed',
    52|  'i prepared',
    53|  'i have prepared',
    54|  'i initialized',
    55|  'i have initialized',
