   223|/**
   224| * Replacement message returned to the owner when a development answer fails the
   225| * guard. Keeps the strict format so the client renders it consistently and the
   226| * owner immediately sees it was blocked rather than a fake success.
   227| */
   228|export function buildBlockedDeveloperExecutionAnswer(violations: string[]): string {
   229|  const reasons = violations.length > 0 ? violations.map((v) => ` - ${v}`).join('\n') : ' - narrative-only response blocked';
